def validar_mediciones(valores: list[float]) -> None:
    if not valores:
        raise ValueError('La lista no puede estar vacía')
    if any(not isinstance(v, (int, float)) for v in valores):
        raise TypeError('Todas las mediciones deben ser numéricas')
    if any(v <= 0 for v in valores):
        raise ValueError('Las mediciones deben ser positivas')

def media(valores: list[float]) -> float:
    validar_mediciones(valores)
    return sum(valores) / len(valores)

resultado = media([10.0, 12.0, 14.0])
print(f'{resultado:.1f} unidades')

def parsear_float(texto: str) -> float:
    try:
        return float(texto)
    except ValueError as error:
        raise ValueError(f'no es un número: {texto!r}') from error

def validar_no_negativo(valor: float, nombre: str) -> float:
    if valor < 0:
        raise ValueError(f'{nombre} debe ser no negativo')
    return valor

def mmol_l_a_mol_l(valor: float) -> float:
    return validar_no_negativo(valor, 'concentración') / 1000.0

resultado = mmol_l_a_mol_l(parsear_float('2.5'))

